@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= CurrentRating ? "filled" : "")"
              @onclick="() => Rate(star)"
              role="button">
            @(star <= CurrentRating ? "★" : "☆")
        </span>
    }
    <span class="rating-info ms-2">
        @if (Recipe.RatingCount > 0)
        {
            <text>@Recipe.AverageRating.ToString("0.0") (@Recipe.RatingCount ratings)</text>
        }
        else
        {
            <text>No ratings yet</text>
        }
    </span>
</div>

@if (Submitted)
{
    <div class="alert alert-success mt-2 py-1 px-2 d-inline-block">Thanks for rating!</div>
}

@code {
    [Parameter] public RecipeCommunity.Models.Recipe Recipe { get; set; } = default!;

    private int CurrentRating { get; set; }
    private bool Submitted { get; set; }

    protected override void OnParametersSet()
    {
        CurrentRating = (int)Math.Round(Recipe.AverageRating);
    }

    private void Rate(int stars)
    {
        CurrentRating = stars;
        Recipe.RatingCount++;
        Recipe.AverageRating = ((Recipe.AverageRating * (Recipe.RatingCount - 1)) + stars) / Recipe.RatingCount;
        Submitted = true;
    }
}

